// Task 3: Bundle size analyzer
export class BundleAnalyzer {
  constructor(buildDir = 'dist') {
    this.buildDir = buildDir;
    this.budgets = {
      main: 100 * 1024, // 100kB gzipped
      vendor: 200 * 1024, // 200kB gzipped
      css: 50 * 1024, // 50kB gzipped
      total: 500 * 1024 // 500kB gzipped total
    };
  }

  async analyzeBundles() {
    try {
      // Read build stats (would be generated by build process)
      const { readFileSync } = await import('fs');
      const { join } = await import('path');
      const statsPath = join(this.buildDir, 'stats.json');
      const stats = JSON.parse(readFileSync(statsPath, 'utf8'));

      return this.processStats(stats);
    } catch (error) {
      // Fallback: analyze from file sizes
      console.warn('Stats file not found, using file size analysis');
      return await this.analyzeFromFileSizes();
    }
  }

  async analyzeFromFileSizes() {
    const { default: fs } = await import('fs');
    const { default: path } = await import('path');
    
    const bundles = {
      js: [],
      css: [],
      total: { size: 0, gzipped: 0 }
    };

    try {
      const files = fs.readdirSync(this.buildDir);

      files.forEach(file => {
        const filePath = path.join(this.buildDir, file);
        const stat = fs.statSync(filePath);

        if (file.endsWith('.js')) {
          bundles.js.push({
            name: file,
            size: stat.size,
            gzipped: this.estimateGzipSize(stat.size)
          });
        } else if (file.endsWith('.css')) {
          bundles.css.push({
            name: file,
            size: stat.size,
            gzipped: this.estimateGzipSize(stat.size)
          });
        }

        bundles.total.size += stat.size;
        bundles.total.gzipped += this.estimateGzipSize(stat.size);
      });

      return this.generateReport(bundles);
    } catch (error) {
      console.error('Error analyzing bundles:', error);
      return null;
    }
  }

  estimateGzipSize(size) {
    // Rough gzip estimation: typically 20-30% of original size for JS/CSS
    return Math.round(size * 0.25);
  }

  generateReport(bundles) {
    const report = {
      timestamp: new Date().toISOString(),
      bundles,
      violations: [],
      recommendations: []
    };

    // Check budgets
    const mainBundle = bundles.js.find(b => b.name.includes('index-'));
    const vendorBundle = bundles.js.find(b => b.name.includes('vendor-'));
    const cssBundle = bundles.css[0];

    if (mainBundle && mainBundle.gzipped > this.budgets.main) {
      report.violations.push({
        type: 'main-bundle-size',
        message: `Main bundle exceeds budget: ${this.formatBytes(mainBundle.gzipped)} > ${this.formatBytes(this.budgets.main)}`,
        severity: 'high'
      });
    }

    if (vendorBundle && vendorBundle.gzipped > this.budgets.vendor) {
      report.violations.push({
        type: 'vendor-bundle-size',
        message: `Vendor bundle exceeds budget: ${this.formatBytes(vendorBundle.gzipped)} > ${this.formatBytes(this.budgets.vendor)}`,
        severity: 'medium'
      });
    }

    if (cssBundle && cssBundle.gzipped > this.budgets.css) {
      report.violations.push({
        type: 'css-bundle-size',
        message: `CSS bundle exceeds budget: ${this.formatBytes(cssBundle.gzipped)} > ${this.formatBytes(this.budgets.css)}`,
        severity: 'medium'
      });
    }

    if (bundles.total.gzipped > this.budgets.total) {
      report.violations.push({
        type: 'total-bundle-size',
        message: `Total bundle exceeds budget: ${this.formatBytes(bundles.total.gzipped)} > ${this.formatBytes(this.budgets.total)}`,
        severity: 'high'
      });
    }

    // Generate recommendations
    if (report.violations.length > 0) {
      report.recommendations.push('Consider code splitting for large bundles');
      report.recommendations.push('Implement lazy loading for heavy components');
      report.recommendations.push('Optimize CSS delivery with critical CSS extraction');
      report.recommendations.push('Use tree shaking to remove unused code');
    }

    return report;
  }

  formatBytes(bytes) {
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  }

  async checkBudgets() {
    const report = await this.analyzeFromFileSizes();
    if (!report) return false;

    const hasViolations = report.violations.length > 0;

    if (hasViolations) {
      console.warn('[Bundle Analysis] Budget violations detected:');
      report.violations.forEach(v => console.warn(`  - ${v.message}`));
      console.log('[Bundle Analysis] Recommendations:');
      report.recommendations.forEach(r => console.log(`  - ${r}`));
    } else {
      console.log('[Bundle Analysis] All bundles within budget ✓');
    }

    return !hasViolations;
  }
}

export const bundleAnalyzer = new BundleAnalyzer();